    let wr = 1.0 / (1e-6 + abs(get_norm_pixel(xi + 2, yi) - c) + abs(get_norm_pixel(xi + 1, yi) - get_norm_pixel(xi - 1, yi)));

    let gv = (wu * gu + wd * gd) / max(wu + wd, 1e-6);
